// ─────────────────────────────────────────────────────────────────────────────
// FrameCodec (Strategy)
// ─────────────────────────────────────────────────────────────────────────────

/** Wire-format strategy: encodes outbound payloads, decodes inbound. */
interface FrameCodec
{
    public function encode(mixed $payload): string;
    /**
     * @param string $buffer Mutable; consumed bytes are removed.
     * @return list<mixed>   Decoded payloads.
     */
    public function decode(string &$buffer): array;
}

/**
 * PVE termproxy text framing.
 *
 * Encoding (client → server) uses `0:LEN:PAYLOAD` (data),
 * `1:COLS:ROWS:` (resize), `2` (ping).
 *
 * Decoding (server → client) is **pass-through**: PVE's termproxy is
 * asymmetric — server→client is the raw underlying TTY output (escape
 * sequences and all), not framed. The only framed inbound message is
 * the initial "OK" ack, which appears immediately after the in-band
 * `<user>:<vncticket>\n` handshake and is harmless to surface verbatim.
 */
final class TextFrameCodec implements FrameCodec
{
    public const PING_FRAME = '2';

    public function encode(mixed $payload): string
    {
        $payload = (string) $payload;
        return sprintf('0:%d:%s%s', strlen($payload), $payload, "\n");
    }

    public static function encodeResize(int $cols, int $rows): string
    {
        return sprintf('1:%d:%d:', $cols, $rows);
    }

    /** @return list<string> */
    public function decode(string &$buffer): array
    {
        if ($buffer === '') return [];
        $messages = [$buffer];
        $buffer = '';
        return $messages;
    }
}

/** VNC: raw RFB protocol bytes pass through unchanged. */
final class BinaryFrameCodec implements FrameCodec
{
    public function encode(mixed $payload): string
    {
        return (string) $payload;
    }

    /** @return list<string> */
    public function decode(string &$buffer): array
    {
        if ($buffer === '') return [];
        $out = [$buffer];
        $buffer = '';
        return $out;
    }
}

