/** Issued ticket + the path prefix used to compose the upgrade URL. */
final class IssuedTicket
{
    public function __construct(
        public readonly ConsoleTicket $ticket,
        public readonly string $basePath,
    ) {}
}

/**
 * Issues a one-shot vncticket for a specific (flow × resource) combo.
 *
 * @template T
 */
interface TicketIssuer
{
    /**
     * @param TerminalTarget|VncTarget $target
     */
    public function issue(Configuration $config, TerminalTarget|VncTarget $target, ?\GuzzleHttp\ClientInterface $http = null): IssuedTicket;
}

abstract class BaseTicketIssuer implements TicketIssuer
{
    public function issue(Configuration $config, TerminalTarget|VncTarget $target, ?\GuzzleHttp\ClientInterface $http = null): IssuedTicket
    {
        $response = $this->callApi($config, $target, $http);
        $data = self::extractData($response);
        return new IssuedTicket(ConsoleTicket::fromArray($data), $this->basePath($target));
    }

    abstract protected function callApi(Configuration $config, TerminalTarget|VncTarget $target, ?\GuzzleHttp\ClientInterface $http): mixed;
    abstract protected function basePath(TerminalTarget|VncTarget $target): string;

    /**
     * Permissively pulls the inner ticket payload out of the typed
     * response wrapper. Different endpoints return slightly different
     * envelopes; handle both `->getData()` and direct array shapes.
     */
    private static function extractData(mixed $response): array
    {
        if (is_array($response)) return $response;
        if (is_object($response) && method_exists($response, 'getData')) {
            $data = $response->getData();
            if (is_array($data)) return $data;
            if (is_object($data) && method_exists($data, 'jsonSerialize')) return (array) $data->jsonSerialize();
            return (array) $data;
        }
        if (is_object($response)) return (array) $response;
        throw new \RuntimeException('unable to extract ticket payload');
    }
}

final class NodeTermproxyIssuer extends BaseTicketIssuer
{
    protected function callApi(Configuration $config, TerminalTarget|VncTarget $t, ?\GuzzleHttp\ClientInterface $http): mixed
    {
        // PVE rejects POSTs with `Content-Type: application/json` and a zero-byte
        // body ("malformed JSON string..."). The PHP generator leaves $httpBody
        // empty when the typed body is null, so we construct an explicit empty
        // DTO to force `{}` on the wire.
        return (new NodesApi($http, $config))->nodesTermproxy($t->node, new NodesTermproxyRequest());
    }
    protected function basePath(TerminalTarget|VncTarget $t): string
    { return '/nodes/' . rawurlencode($t->node); }
}

