/** Open/closed: add a new flow → register one new issuer here. */
final class TicketIssuerRegistry
{
    /** @var array<string, TicketIssuer> */
    private array $terminal;
    /** @var array<string, TicketIssuer> */
    private array $vnc;

    public function __construct()
    {
        $this->terminal = [
            TerminalTarget::KIND_NODE => new NodeTermproxyIssuer(),
            TerminalTarget::KIND_QEMU => new QemuTermproxyIssuer(),
            TerminalTarget::KIND_LXC => new LxcTermproxyIssuer(),
        ];
        $this->vnc = [
            VncTarget::KIND_NODE_SHELL => new NodeVncShellIssuer(),
            VncTarget::KIND_QEMU => new QemuVncproxyIssuer(),
            VncTarget::KIND_LXC => new LxcVncproxyIssuer(),
        ];
    }

    public function forTerminal(TerminalTarget $target): TicketIssuer
    {
        return $this->terminal[$target->kind] ?? throw new \InvalidArgumentException("unsupported terminal target kind: {$target->kind}");
    }

    public function forVnc(VncTarget $target): TicketIssuer
    {
        return $this->vnc[$target->kind] ?? throw new \InvalidArgumentException("unsupported VNC target kind: {$target->kind}");
    }
}

