interface AuthAttacher
{
    /** @return array<string, string> */
    public function headers(Configuration $config): array;
}

final class CompositeAuthAttacher implements AuthAttacher
{
    /** @param list<AuthAttacher> $inner */
    public function __construct(private readonly array $inner) {}

    public function headers(Configuration $config): array
    {
        $merged = [];
        foreach ($this->inner as $a) {
            $merged = array_merge($merged, $a->headers($config));
        }
        return $merged;
    }
}

final class TokenAuthAttacher implements AuthAttacher
{
    public function headers(Configuration $config): array
    {
        $token = $config->getApiKey('Authorization');
        if (!empty($token)) {
            $prefix = $config->getApiKeyPrefix('Authorization') ?? '';
            return ['Authorization' => $prefix === '' ? $token : "$prefix $token"];
        }
        $access = $config->getAccessToken();
        if (!empty($access)) {
            return ['Authorization' => "PVEAPIToken=$access"];
        }
        return [];
    }
}

final class CookieAuthAttacher implements AuthAttacher
{
    public function headers(Configuration $config): array
    {
        $cookie = $config->getApiKey('PVEAuthCookie');
        return !empty($cookie) ? ['Cookie' => "PVEAuthCookie=$cookie"] : [];
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// WebSocketTransport (Adapter)
// ─────────────────────────────────────────────────────────────────────────────

interface WebSocketTransport
{
    /** @param array<string, string> $headers */
    public function open(string $url, array $headers): mixed;
}

final class TextalkTransport implements WebSocketTransport
{
    /** @param array<string,mixed> $extraOptions Passed verbatim to `WebSocket\Client` (e.g. `context` for stream_context_create). */
    public function __construct(private readonly array $extraOptions = []) {}

    public function open(string $url, array $headers): mixed
    {
        if (!class_exists(\WebSocket\Client::class)) {
            throw new \RuntimeException(
                'PHP WebSocket support requires the optional `textalk/websocket` package. ' .
                'Install with: composer require textalk/websocket'
            );
        }
        return new \WebSocket\Client($url, array_merge([
            'headers' => $headers,
            'timeout' => 60,
        ], $this->extraOptions));
    }

    /**
     * Convenience constructor for self-signed PVE TLS. Matches the
     * `verify=false` semantics of the Guzzle option used by the rest
     * of the SDK.
     */
    public static function insecure(): self
    {
        return new self([
            'context' => stream_context_create([
                'ssl' => [
                    'verify_peer' => false,
                    'verify_peer_name' => false,
                    'allow_self_signed' => true,
                ],
            ]),
        ]);
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// UrlBuilder
// ─────────────────────────────────────────────────────────────────────────────

final class UpgradeUrlBuilder
{
    public static function build(Configuration $config, string $basePath, ConsoleTicket $ticket): string
    {
        $host = rtrim($config->getHost(), '/');
        $ws = match (true) {
            str_starts_with($host, 'https://') => 'wss://' . substr($host, 8),
            str_starts_with($host, 'http://') => 'ws://' . substr($host, 7),
            default => $host,
        };
        return "$ws$basePath/vncwebsocket?" . http_build_query([
            'port' => $ticket->port,
            'vncticket' => $ticket->ticket,
        ]);
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// Sessions
// ─────────────────────────────────────────────────────────────────────────────

abstract class BaseSession
{
    protected bool $closed = false;

    public function __construct(protected readonly mixed $socket) {}

    public function close(): void
    {
        if ($this->closed) return;
        $this->closed = true;
        try {
            $this->socket->close();
        } catch (\Throwable) {}
    }
}

final class TerminalSession extends BaseSession
{
    private readonly TextFrameCodec $codec;
    private string $buffer = '';
    private int $lastPing;

    public function __construct(mixed $socket)
    {
        parent::__construct($socket);
        $this->codec = new TextFrameCodec();
        $this->lastPing = time();
    }

    public function send(string $text): void
    {
        $this->socket->send($this->codec->encode($text));
    }

    public function resize(int $cols, int $rows): void
    {
        $this->socket->send(TextFrameCodec::encodeResize($cols, $rows));
    }

    /** Read the next data payload. Blocks until a 0-frame or close. */
    public function recv(): ?string
    {
        while (true) {
            $messages = $this->codec->decode($this->buffer);
            if (!empty($messages)) return $messages[0];
            if (time() - $this->lastPing >= 30) {
                $this->socket->send(TextFrameCodec::PING_FRAME);
                $this->lastPing = time();
            }
            try {
                $chunk = $this->socket->receive();
            } catch (\Throwable) {
                $this->closed = true;
                return null;
            }
            if ($chunk === null || $chunk === '') {
                $this->closed = true;
                return null;
            }
            $this->buffer .= (string) $chunk;
        }
    }
}

final class VncSession extends BaseSession
{
    private readonly BinaryFrameCodec $codec;

    public function __construct(mixed $socket)
    {
        parent::__construct($socket);
        $this->codec = new BinaryFrameCodec();
    }

    public function send(string $bytes): void
    {
        $this->socket->binary($this->codec->encode($bytes));
    }

    /** Read the next binary frame. Blocks until one arrives. */
    public function recv(): ?string
    {
        try {
            $chunk = $this->socket->receive();
        } catch (\Throwable) {
            $this->closed = true;
            return null;
        }
        return $chunk === null ? null : (string) $chunk;
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// ConsoleConnector (Template Method)
// ─────────────────────────────────────────────────────────────────────────────

final class ConsoleConnector
{
    public function __construct(
        private readonly TicketIssuerRegistry $registry = new TicketIssuerRegistry(),
        private readonly AuthAttacher $auth = new CompositeAuthAttacher([
            new TokenAuthAttacher(),
            new CookieAuthAttacher(),
        ]),
        private readonly WebSocketTransport $transport = new TextalkTransport(),
        private readonly ?\GuzzleHttp\ClientInterface $http = null,
    ) {}

    public function connectTerminal(Configuration $config, TerminalTarget $target): TerminalSession
    {
        $issued = $this->registry->forTerminal($target)->issue($config, $target, $this->http);
        $url = UpgradeUrlBuilder::build($config, $issued->basePath, $issued->ticket);
        $socket = $this->transport->open($url, $this->auth->headers($config));
        // PVE termproxy expects `<user>:<vncticket>\n` as the very first
        // frame after the WS handshake. textalk/websocket's `Client`
        // constructor returns once the upgrade is complete, so the
        // socket is already open here — push the auth inline.
        $socket->send($issued->ticket->user . ':' . $issued->ticket->ticket . "\n");
        return new TerminalSession($socket);
    }

    public function connectVnc(Configuration $config, VncTarget $target): VncSession
    {
        $issued = $this->registry->forVnc($target)->issue($config, $target, $this->http);
        $url = UpgradeUrlBuilder::build($config, $issued->basePath, $issued->ticket);
        $socket = $this->transport->open($url, $this->auth->headers($config));
        return new VncSession($socket);
    }
}

// Legacy facade kept for backwards compatibility with the previous
// (pre-refactor) call sites.
final class WebSocket
{
    public static function connectTerminal(Configuration $config, TerminalTarget $target): TerminalSession
    {
        return (new ConsoleConnector())->connectTerminal($config, $target);
    }

    public static function connectVnc(Configuration $config, VncTarget $target): VncSession
    {
        return (new ConsoleConnector())->connectVnc($config, $target);
    }
}
